mapper.select:
/** CmmtQnaDao.select */
select

from cmmt_qna
where
	qna_id = #{qnaId}

/** CmmtQnaDao.selectList */
select

from cmmt_qna
where
	1=1

		and system_id = #{systemId}


		and qna_id = #{qnaId}


		and qna_nm like '%' || #{qnaNm} || '%'


		and enabled = #{enabled}

order by
	qna_id

mapper.insert:
/** CmmtQnaDao.insert */
insert into cmmt_qna (
	 qna_id
	,qna_nm
	,system_id
	,article_cnt
	,category
	,category_code_group
	,attachable
	,attachment_size
	,attachment_ext
	,enabled
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{qnaId}
	,#{qnaNm}
	,#{systemId}
	,#{articleCnt}
	,#{category}
	,#{categoryCodeGroup}
	,#{attachable}
	,#{attachmentSize}
	,#{attachmentExt}
	,#{enabled}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtQnaDao.update */
update cmmt_qna set
	 qna_nm              = #{qnaNm}
	,system_id           = #{systemId}
	,article_cnt         = #{articleCnt}
	,category            = #{category}
	,category_code_group = #{categoryCodeGroup}
	,attachable          = #{attachable}
	,attachment_size     = #{attachmentSize}
	,attachment_ext      = #{attachmentExt}
	,enabled             = #{enabled}
	,creator_id          = #{creatorId}
	,created_dt          = #{createdDt}
	,updater_id          = #{updaterId}
	,updated_dt          = #{updatedDt}
where
	qna_id = #{qnaId}

mapper.delete:
/** CmmtQnaDao.delete */
delete from cmmt_qna
where
	qna_id = #{qnaId}
